async (params, browser) => {
  // Search Pinterest for pins
  await browser.open(`https://www.pinterest.com/search/pins/?q=${params.query}`)

  // Wait for pin results to load
  await browser.waitForSelector('[data-test-id=\'pin\'], [data-test-id=\'pinWrapper\'], div[data-grid-item]', 15000)

  // Let results fully render
  await browser.wait(3000)

  // Extract pin search results
  const search_results = await browser.evaluate(`const results = []; const pins = document.querySelectorAll('[data-test-id="pin"], [data-test-id="pinWrapper"], div[data-grid-item]'); for (let i = 0; i < Math.min(pins.length, 20); i++) { const pin = pins[i]; const imgEl = pin.querySelector('img'); const linkEl = pin.querySelector('a[href*="/pin/"]'); const titleEl = pin.querySelector('[data-test-id="pinTitle"], [title]') || imgEl; const descEl = pin.querySelector('[data-test-id="truncated-description"], [data-test-id="pin-description"]'); results.push({ title: titleEl ? (titleEl.getAttribute('title') || titleEl.getAttribute('alt') || titleEl.textContent || '').trim().slice(0, 200) : '', image_url: imgEl ? (imgEl.getAttribute('src') || '') : '', pin_url: linkEl ? 'https://www.pinterest.com' + linkEl.getAttribute('href') : '', description: descEl ? descEl.textContent.trim().slice(0, 300) : '' }); } return { query: '' + params.query + '', result_count: results.length, results: results }`)

  return search_results
}
